// Prepare a structured summary for Gemini AI priorities analysis.
// Only pass explicit state-change counts — never raw capture text.
const d = $input.first().json;

let weekSummary = [
  `Weekly capture data (last ${d.window_days} days):`,
  `- New captures: ${d.new_captures_count}`,
  `- Filed notes: ${d.filed_notes_count}`,
  `- Tasks created: ${d.created_tasks_count}`,
  `- Actions completed (done/fix): ${d.completed_actions_count}`,
  `- Decisions recorded: ${d.decisions_count}`,
  `- Inbox backlog: ${d.inbox_backlog_count}`,
  `- Corrections applied: ${d.corrections_count}`,
  `- Terminal failures: ${d.failures_count}`,
  `- Retries scheduled: ${d.retries_count}`,
  `- Sensitive rejections: ${d.sensitive_rejections_count}`,
].join('\n');

if (d.outstanding_tasks_count !== null && d.outstanding_tasks_count !== undefined) {
  weekSummary += `\n- Outstanding open tasks: ${d.outstanding_tasks_count}`;
}

const prompt = [
  'You are a weekly review assistant for a personal knowledge management system.',
  'Based only on the following objective statistics (no raw content), generate a concise',
  'priorities section of 3-5 bullet points. Each bullet must be grounded in the numbers.',
  'Do not infer intent or completion from vague prose. Focus on what the numbers suggest.',
  'Label your output clearly as AI-GENERATED PRIORITIES.',
  '',
  weekSummary,
].join('\n');

return [{ json: { prompt, week_data: d } }];

// Combine weekly stats with AI priorities into a Discord message.
const geminiResponse = $input.first().json;
const weekData = $('Prepare AI Priorities Input').first().json.week_data;

const aiText = geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text ?? '(priorities unavailable)';

const ts = new Date(weekData.generated_at).toLocaleString('en-US', {
  timeZone: 'UTC', month: 'short', day: 'numeric',
  hour: '2-digit', minute: '2-digit', hour12: false,
});

const lines = [
  `**Second Brain – Weekly Review** (${ts} UTC)`,
  '',
  '**Captures (last 7 days)**',
  `  New captures: ${weekData.new_captures_count}`,
  `  Filed notes: ${weekData.filed_notes_count}`,
  `  Sensitive rejections: ${weekData.sensitive_rejections_count}`,
  '',
  '**Explicit State Changes**',
  `  Tasks created: ${weekData.created_tasks_count}`,
  `  Actions completed (done/fix): ${weekData.completed_actions_count}`,
  `  Decisions recorded: ${weekData.decisions_count}`,
  `  Corrections applied: ${weekData.corrections_count}`,
  '',
  '**Backlog**',
  `  Inbox: ${weekData.inbox_backlog_count}`,
];

if (weekData.outstanding_tasks_count !== null && weekData.outstanding_tasks_count !== undefined) {
  lines.push(`  Outstanding open tasks: ${weekData.outstanding_tasks_count}`);
}

lines.push(
  '',
  '**Failures & Retries**',
  `  Terminal failures: ${weekData.failures_count}`,
  `  Retries scheduled: ${weekData.retries_count}`,
  '',
  '---',
  '**⚠️ AI-GENERATED PRIORITIES** *(review before acting)*',
  '',
  aiText.trim(),
);

return [{ json: { content: lines.join('\n') } }];
